import initSqlJs from 'https://cdn.jsdelivr.net/npm/sql.js@1/+esm';
const SQL = await initSqlJs({ locateFile: () => 'https://cdn.jsdelivr.net/npm/sql.js@1.14.1/dist/sql-wasm-browser.wasm' });
const db = new SQL.Database(data.databaseBytes ? Uint8Array.from(data.databaseBytes) : undefined);
if (data.setupSql) db.run(data.setupSql);
const resultSets = db.exec(data.query, data.params);

